@namespace Lumeo

@*
    FeatureGrid — responsive 1/2/3-column grid for landing-page feature
    callouts. Part of the 3.4 Splash Kit. Pair with <FeatureItem> children
    or pass raw ChildContent for full control.
*@

<section class="@CssClass" aria-labelledby="@TitleId" @attributes="AdditionalAttributes">
    <div class="mx-auto max-w-6xl px-6 py-16">
        @if (!string.IsNullOrEmpty(Title))
        {
            <h2 id="@TitleId" class="text-3xl font-bold tracking-tight text-foreground text-center">@Title</h2>
        }
        @if (!string.IsNullOrEmpty(Subtitle))
        {
            <p class="mt-3 text-muted-foreground text-center max-w-2xl mx-auto">@Subtitle</p>
        }
        <div class="@($"mt-12 grid gap-8 {ColumnsClass}")">
            @ChildContent
        </div>
    </div>
</section>

@code {
    /// <summary>Centered heading above the grid. Also names the <c>&lt;section&gt;</c>
    /// landmark via <c>aria-labelledby</c>. Omitted when null/empty.</summary>
    [Parameter] public string? Title { get; set; }
    /// <summary>Centered supporting text below <see cref="Title"/>.</summary>
    [Parameter] public string? Subtitle { get; set; }
    /// <summary>Number of columns at the widest breakpoint: 1, 2, 3 (default) or 4.
    /// Any other value falls back to the 3-column layout.</summary>
    [Parameter] public int Columns { get; set; } = 3;
    /// <summary>The feature callouts, typically <see cref="FeatureItem"/> instances.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the root <c>section</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root <c>section</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("w-full", Class);

    // Name the <section> landmark via its heading so AT exposes it as a region
    // with an accessible name (#299). Null when there's no Title.
    private readonly string _titleId = $"featuregrid-title-{Guid.NewGuid():N}";
    private string? TitleId => string.IsNullOrEmpty(Title) ? null : _titleId;

    private string ColumnsClass => Columns switch
    {
        1 => "grid-cols-1",
        2 => "grid-cols-1 sm:grid-cols-2",
        4 => "grid-cols-1 sm:grid-cols-2 lg:grid-cols-4",
        _ => "grid-cols-1 sm:grid-cols-2 lg:grid-cols-3"
    };
}
